#include <stdio.h>
#include <stdlib.h>

int main() {
    // Static allocation
    int static_array[100];  // Fixed size at compile time

    // Dynamic allocation using malloc
    int *dynamic_array = (int*)malloc(100 * sizeof(int));

    if (dynamic_array == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Use the allocated memory
    for (int i = 0; i < 100; i++) {
        dynamic_array[i] = i * 2;
    }

    // Realloc - increase size if needed
    int *larger_array = (int*)realloc(dynamic_array, 200 * sizeof(int));

    if (larger_array != NULL) {
        dynamic_array = larger_array;
    }

    // Free memory when done
    free(dynamic_array);

    return 0;
}

class MemoryManager:
    def __init__(self, total_memory):
        self.total_memory = total_memory
        self.allocated = {}  # {pid: (start, size)}
        self.free_holes = [(0, total_memory)]

    def allocate(self, pid, size):
        """First fit allocation"""
        for i, (start, hole_size) in enumerate(self.free_holes):
            if hole_size >= size:
                self.allocated[pid] = (start, size)

                # Create new hole if space remains
                if hole_size > size:
                    self.free_holes[i] = (start + size, hole_size - size)
                else:
                    self.free_holes.pop(i)

                print(f"Process {pid} allocated: {size}KB at address {start}")
                return start

        print(f"Process {pid} allocation failed: insufficient memory")
        return -1

    def deallocate(self, pid):
        """Free allocated memory"""
        if pid in self.allocated:
            start, size = self.allocated.pop(pid)
            self.free_holes.append((start, size))
            self.free_holes.sort()  # Sort by address
            print(f"Process {pid} deallocated: {size}KB from address {start}")

# Example usage
mm = MemoryManager(1000)  # 1000 KB total memory
mm.allocate(1, 200)  # Allocate 200KB to process 1
mm.allocate(2, 300)  # Allocate 300KB to process 2
mm.allocate(3, 150)  # Allocate 150KB to process 3
mm.deallocate(2)      # Free process 2 memory
